48	
49	export interface ClaimResult {
50	  payout: number;
51	  remainingCap: number;
52	}
53	
54	const INSURANCE_VALUES: Record<string, number> = {
55	  sword: 1000,
56	  amulet: 600,
57	  staff: 800,
58	  potion: 400,
59	  rune: 250,
60	  moonstone: 250,
61	};
62	const DEDUCTIBLE = 100;
63	const CAP_MULTIPLIER = 2;
64	
65	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
66	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
67	
68	function reimbursableAmount(item: Item | undefined, damageAmount: number): number {
69	  const isHighEnchantment = (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
70	  return isHighEnchantment ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : damageAmount;
71	}
72	
73	export function claim(policy: Policy, incident: Incident): ClaimResult {
74	  const insuranceSum = policy.items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
75	  const cap = CAP_MULTIPLIER * insuranceSum;
76	  const payout = incident.damages.reduce((sum, damage) => {
77	    const item = policy.items.find((policyItem) => policyItem.type === damage.itemType);
78	    const reimbursable = reimbursableAmount(item, damage.amount);
79	    return sum + Math.max(0, reimbursable - DEDUCTIBLE);
80	  }, 0);
81	  return { payout, remainingCap: cap - payout };
82	}
83	
84	export function quote(customer: Customer, items: Item[]): number {
85	  const percentageSurcharge = (rate: number, applies: (item: Item) => boolean): number =>
86	    items.filter(applies).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
87	
88	  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
89	  // A block of exactly COMPONENTS_PER_BLOCK alike components (same type) replaces their summed base with COMPONENT_BLOCK_BASE.
90	  const blockAdjustment = COMPONENT_TYPES.reduce((adjustment, componentType) => {
91	    const count = items.filter((item) => item.type === componentType).length;
92	    const replacement = COMPONENT_BLOCK_BASE - COMPONENTS_PER_BLOCK * BASE_PREMIUMS[componentType];
93	    return count === COMPONENTS_PER_BLOCK ? adjustment + replacement : adjustment;
94	  }, 0);
95	  const curseSurcharge = percentageSurcharge(CURSE_SURCHARGE_RATE, (item) => item.cursed === true);
96	  const highEnchantmentSurcharge = percentageSurcharge(
97	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
98	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
99	  );
100	  const adjustedBase = baseSum + blockAdjustment;
101	  const proportionalDiscount = (rate: number, qualifies: boolean): number => (qualifies ? adjustedBase * rate : 0);
102	  const firstInsurance = adjustedBase * FIRST_INSURANCE_RATE;
103	  const loyaltyDiscount = proportionalDiscount(LOYALTY_DISCOUNT_RATE, customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD);
104	  const followUpDiscount = proportionalDiscount(FOLLOW_UP_DISCOUNT_RATE, (customer.previousContracts ?? 0) >= FOLLOW_UP_CONTRACTS_THRESHOLD);
105	  return Math.ceil(adjustedBase + curseSurcharge + highEnchantmentSurcharge + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
106	}
